{
  "domain_analysis": {
    "business_context": "Evolution of a delivery platform's core domain model from a 1:1 Shipment-Recipient relationship to a 1:N relationship. This is a fundamental structural change to the aggregate root, not a simple field addition. It changes the identity semantics of a Shipment — a Shipment is no longer 'a delivery to a person' but becomes 'a delivery to a set of people with potentially divergent preferences.' This has cascading implications for routing, billing, proof-of-delivery, notifications, SLA tracking, and partner integrations.",
    "bounded_context": "Shipment Fulfillment / Order Management",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A logistical unit representing the transport of goods from origin to one or more recipients. The aggregate root in this context." },
      { "term": "Recipient", "definition": "A party designated to receive goods within a Shipment. Identified by name, address, phone number, and delivery preferences. Transitions from a value object embedded in Shipment to a first-class entity within the Shipment aggregate." },
      { "term": "Delivery Preferences", "definition": "Recipient-specific instructions governing how delivery should occur (e.g., time window, safe place, signature required, leave with neighbor). Each Recipient within a Shipment may have distinct preferences." },
      { "term": "Primary Recipient", "definition": "The first or default recipient on a Shipment. Critical for backward compatibility — legacy shipments and partner APIs assume this role implicitly." },
      { "term": "Multi-Recipient Shipment", "definition": "A Shipment with more than one Recipient. Raises questions about partial fulfillment, split delivery, and per-recipient status tracking." },
      { "term": "Proof of Delivery (POD)", "definition": "Evidence that goods were delivered. In a multi-recipient model, POD must be captured per-Recipient, not per-Shipment." },
      { "term": "Shipment Status", "definition": "The lifecycle state of a Shipment. In a multi-recipient model, this must reconcile potentially divergent per-recipient delivery outcomes into a coherent aggregate status." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment must have at least one Recipient at all times.",
      "invariant": true,
      "invariant_justification": "A Shipment with zero recipients is physically meaningless — there is no destination. This is a structural integrity constraint.",
      "testable_assertion": "Any attempt to create a Shipment with an empty recipient list, or to remove the last Recipient from a Shipment, must be rejected."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient within a Shipment must have a valid name, address, and phone number.",
      "invariant": true,
      "invariant_justification": "These are the minimum fields required to attempt delivery. Without them, the courier cannot fulfill the shipment. This is a data consistency constraint inherited from the original model.",
      "testable_assertion": "Persisting a Recipient with a null or empty name, address, or phone number must be rejected at the domain level."
    },
    {
      "id": "BR-3",
      "rule": "Delivery preferences are optional per Recipient and default to the Shipment-level defaults if not specified.",
      "invariant": false,
      "invariant_justification": "Delivery preferences are a policy decision. The defaults and which preferences exist can change with product evolution.",
      "testable_assertion": "A Recipient created without explicit delivery preferences must inherit the Shipment's default preferences. A Recipient with explicit preferences must use those instead."
    },
    {
      "id": "BR-4",
      "rule": "All existing single-recipient shipments must remain valid and queryable without data loss after migration.",
      "invariant": true,
      "invariant_justification": "Corrupting or losing 2 million production shipment records would be a data integrity catastrophe with legal, financial, and operational consequences.",
      "testable_assertion": "After migration, every pre-existing Shipment must return exactly one Recipient with the same name, address, and phone number as before."
    },
    {
      "id": "BR-5",
      "rule": "Shipment status must reflect the aggregate delivery outcome across all Recipients.",
      "invariant": true,
      "invariant_justification": "A Shipment cannot be marked 'Delivered' if some Recipients have not received their goods. The aggregate status must be a consistent projection of per-recipient states — otherwise reporting, billing, and SLA calculations are corrupt.",
      "testable_assertion": "A Shipment with 3 Recipients where 2 are delivered and 1 is pending must NOT have status 'Delivered'. The system must define and enforce a status reconciliation rule (e.g., 'Partially Delivered', or 'Delivered' only when all Recipients are fulfilled)."
    },
    {
      "id": "BR-6",
      "rule": "Proof of Delivery must be captured and stored per Recipient, not per Shipment.",
      "invariant": true,
      "invariant_justification": "In a multi-recipient model, each recipient is a distinct delivery event. A single POD for the Shipment would be meaningless if recipients are at different addresses. This is a physical constraint of the delivery process.",
      "testable_assertion": "Each Recipient in a multi-recipient Shipment must have an independent POD record. Querying POD for a Shipment must return a collection of per-recipient PODs."
    },
    {
      "id": "BR-7",
      "rule": "External partner APIs must continue to receive shipment data in a backward-compatible format during a transition period.",
      "invariant": false,
      "invariant_justification": "This is an integration policy, not a physical constraint. Partners can be migrated on a timeline, but it requires coordination rather than being an immutable law.",
      "testable_assertion": "Partner API payloads for single-recipient shipments must be structurally identical to the current format. Multi-recipient shipments must either be sent in a versioned format or flattened to Primary Recipient for legacy partners."
    },
    {
      "id": "BR-8",
      "rule": "Recipient ordering within a Shipment must be deterministic and stable.",
      "invariant": true,
      "invariant_justification": "Route optimization, billing allocation, and partner API compatibility (Primary Recipient) all depend on a stable, predictable ordering. Non-deterministic ordering would cause data inconsistency across systems.",
      "testable_assertion": "Recipients must have an explicit ordinal position. Querying a Shipment's recipients must always return them in the same order. The first recipient (position 0 or 1) is the Primary Recipient."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new Shipment is being created",
      "when": "The caller provides a list of one or more Recipients, each with name, address, phone, and optional delivery preferences",
      "then": "The Shipment is created with all Recipients persisted in the specified order, and the first Recipient is designated as the Primary Recipient"
    },
    {
      "id": "AC-2",
      "given": "A new Shipment is being created",
      "when": "The caller provides an empty recipient list or omits recipients entirely",
      "then": "The system rejects the request with a validation error indicating at least one Recipient is required"
    },
    {
      "id": "AC-3",
      "given": "An existing single-recipient Shipment created before migration",
      "when": "The Shipment is queried via the new API",
      "then": "It returns a recipient list containing exactly one Recipient with the original name, address, and phone number, and that Recipient is the Primary Recipient"
    },
    {
      "id": "AC-4",
      "given": "A multi-recipient Shipment where 2 of 3 Recipients have been delivered",
      "when": "The Shipment status is queried",
      "then": "The status reflects 'Partially Delivered' (or equivalent), not 'Delivered'"
    },
    {
      "id": "AC-5",
      "given": "A multi-recipient Shipment",
      "when": "A delivery is completed for one Recipient with a signature capture",
      "then": "A POD record is created for that specific Recipient only; other Recipients' POD status is unaffected"
    },
    {
      "id": "AC-6",
      "given": "A legacy partner integration consuming shipment data",
      "when": "A single-recipient Shipment is transmitted",
      "then": "The payload structure is identical to the pre-migration format with no breaking changes"
    },
    {
      "id": "AC-7",
      "given": "A legacy partner integration consuming shipment data",
      "when": "A multi-recipient Shipment is transmitted",
      "then": "The system either sends only the Primary Recipient in the legacy format, or uses a versioned endpoint that the partner has opted into"
    },
    {
      "id": "AC-8",
      "given": "A Shipment with multiple Recipients",
      "when": "A caller attempts to remove the last remaining Recipient",
      "then": "The system rejects the operation, preserving the invariant that a Shipment must have at least one Recipient"
    },
    {
      "id": "AC-9",
      "given": "A Recipient within a Shipment has no explicit delivery preferences set",
      "when": "The delivery preferences for that Recipient are resolved",
      "then": "The system applies the Shipment-level default delivery preferences"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Two Recipients on the same Shipment have the same address but different delivery preferences",
      "expected_behavior": "Both Recipients are treated as distinct deliveries. Route optimization may consolidate the stop, but POD and notification must be handled separately per Recipient."
    },
    {
      "scenario": "A Recipient is added to a Shipment that is already in-transit",
      "expected_behavior": "The system must define whether mid-flight recipient changes are allowed. If allowed, the courier must be notified and the route recalculated. If not allowed, the request is rejected. This is a critical business decision that needs product input."
    },
    {
      "scenario": "A multi-recipient Shipment has one Recipient refuse delivery",
      "expected_behavior": "The refused Recipient gets a 'Refused' POD status. The Shipment continues to other Recipients. Shipment status becomes 'Partially Delivered' or 'Delivered with Exceptions' once all attempts are complete."
    },
    {
      "scenario": "Migration runs on 2 million records and fails midway",
      "expected_behavior": "Migration must be idempotent and resumable. Partially migrated data must not corrupt queries. A rollback path must exist that restores the original schema without data loss."
    },
    {
      "scenario": "Partner API receives a webhook for a multi-recipient Shipment event but only understands single-recipient format",
      "expected_behavior": "The integration layer must transform the event to reference the Primary Recipient only, or queue the event until the partner has been upgraded. Silent data loss (dropping extra recipients without logging) is unacceptable."
    },
    {
      "scenario": "Billing for a multi-recipient Shipment — is it one charge or N charges?",
      "expected_behavior": "This is an unresolved business question. The billing model must be explicitly decided: per-shipment (flat), per-recipient, or per-stop. This decision cascades into invoicing, refunds, and partner settlements."
    },
    {
      "scenario": "Notifications (SMS/email) for delivery updates on a multi-recipient Shipment",
      "expected_behavior": "Each Recipient must receive notifications relevant only to their own delivery, not the entire Shipment. The sender/shipper should receive a consolidated view."
    },
    {
      "scenario": "Duplicate Recipient (same name, address, phone) added to a Shipment",
      "expected_behavior": "System should warn but not necessarily reject — legitimate scenarios exist (e.g., two packages to the same person). However, exact duplicates including preferences should be flagged as likely user error."
    }
  ],

  "business_impact": {
    "financial": "High. Billing model must be redefined for multi-recipient shipments (per-shipment vs per-recipient pricing). Existing contracts with partners may assume 1:1 pricing. Revenue opportunity: multi-recipient shipments could command premium pricing. Risk: incorrect billing logic during transition could cause revenue leakage or overcharging disputes.",
    "operational": "Very High. Route optimization algorithms must handle multiple stops per shipment. Courier mobile apps must display per-recipient checklists. Dispatch logic, SLA calculations, and reporting dashboards all assume 1:1 and must be updated. Data migration of 2M records requires a carefully staged rollout with rollback capability.",
    "user": "Moderate-to-High. Senders get new capability (multi-recipient). Recipients should see no degradation. Couriers need updated workflows — delivering to multiple recipients per shipment changes their task model. Poor UX on the courier side could slow delivery times.",
    "risk": "High. This is a change to the core aggregate root of the domain. Risks include: (1) data migration failure corrupting 2M records, (2) partner API breakage causing integration outages, (3) inconsistent status reporting leading to SLA violations, (4) billing errors during transition, (5) notification spam or missed notifications. The blast radius is the entire platform.",
    "stakeholders_affected": [
      { "group": "Senders/Shippers", "impact": "Gain multi-recipient capability. Must learn new UI/API. Existing single-recipient workflows must remain unchanged." },
      { "group": "Recipients", "impact": "Should be transparent. Must not receive notifications for other recipients on the same shipment. POD must be individual." },
      { "group": "Couriers/Drivers", "impact": "Workflow changes significantly. Must handle per-recipient delivery confirmation, potentially multiple stops per shipment. Training required." },
      { "group": "External Partners (API consumers)", "impact": "Breaking change if not handled with backward compatibility. Requires versioned API strategy and coordinated migration timeline." },
      { "group": "Finance/Billing Team", "impact": "Must define new pricing model. Reconciliation logic changes. Existing invoicing pipelines may break." },
      { "group": "Operations/Dispatch", "impact": "Route optimization, SLA tracking, and reporting all need updates. Partial delivery states add complexity to ops dashboards." },
      { "group": "Customer Support", "impact": "Must handle new failure modes (partial delivery, per-recipient disputes). Need updated tooling and training." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec describes WHAT is changing (1:1 to 1:N) but leaves critical business decisions unresolved: billing model, mid-transit recipient changes, shipment status reconciliation rules, and partner migration strategy. These are not implementation details — they are business policy decisions that fundamentally shape the domain model. Without them, acceptance criteria for billing, status, and partner integration are best-effort assumptions.",
    "high_confidence_areas": [
      "The Recipient must become a collection within Shipment with minimum cardinality of 1",
      "Backward compatibility for existing 2M records is non-negotiable",
      "POD must move to per-Recipient granularity",
      "Partner API backward compatibility requires an explicit strategy",
      "Delivery preferences must be per-Recipient"
    ],
    "low_confidence_areas": [
      "Billing model for multi-recipient shipments (per-shipment vs per-recipient vs per-stop)",
      "Whether recipients can be added/removed from in-transit shipments",
      "Exact status reconciliation rules (what constitutes 'Delivered' for a multi-recipient shipment)",
      "Partner migration timeline and whether legacy format is maintained indefinitely or sunset",
      "Whether a Shipment with multiple recipients is one route stop or multiple stops"
    ],
    "assumptions": [
      "The first Recipient in the list serves as Primary Recipient for backward compatibility",
      "Delivery preferences have sensible Shipment-level defaults",
      "Migration will be online (no downtime) given 2M records in production",
      "Partner APIs will need a transition period, not a hard cutover",
      "Recipient is an entity within the Shipment aggregate, not a separate aggregate"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "Billing model for multi-recipient shipments is undefined. Is a multi-recipient shipment billed as one shipment, per-recipient, or per-delivery-stop? This decision affects pricing, invoicing, refunds, and partner settlements. It cannot be deferred — the domain model structure depends on it.",
      "affected_stakeholders": ["Finance/Billing Team", "Senders/Shippers", "External Partners"],
      "options": [
        "A) Per-Shipment flat rate — simple, but may underprice complex multi-recipient deliveries",
        "B) Per-Recipient pricing — fair but requires new billing entities and potentially breaks existing contracts",
        "C) Per-Stop pricing — accounts for route consolidation but requires tight coupling with routing engine"
      ],
      "recommendation": "Option B (per-Recipient) aligns best with the domain change and is most transparent to customers. Recommend product and finance define this before implementation begins."
    },
    {
      "type": "ambiguity",
      "description": "Shipment status reconciliation for multi-recipient shipments is undefined. When a Shipment has 3 Recipients and only 2 are delivered, what is the Shipment-level status? The spec does not define partial delivery states or the rules for aggregating per-recipient status into shipment status.",
      "affected_stakeholders": ["Operations/Dispatch", "Customer Support", "Senders/Shippers"],
      "options": [
        "A) Introduce 'Partially Delivered' status — most accurate but adds complexity to all downstream consumers of shipment status",
        "B) Shipment is 'Delivered' only when ALL recipients are fulfilled — simple rule but delays status finalization",
        "C) Shipment status is decoupled; only per-recipient status matters — cleanest model but breaks existing reporting"
      ],
      "recommendation": "Option A with Option B as the rule for the final 'Delivered' state. 'Partially Delivered' gives operational visibility; 'Delivered' requires 100% fulfillment. Requires explicit product sign-off."
    },
    {
      "type": "ambiguity",
      "description": "Mutability of recipient list during shipment lifecycle is undefined. Can recipients be added or removed after a shipment is created? After it is dispatched? After it is in-transit? This has major implications for routing, courier workflow, and billing.",
      "affected_stakeholders": ["Couriers/Drivers", "Operations/Dispatch", "Senders/Shippers"],
      "options": [
        "A) Recipients are immutable after shipment creation — simplest, safest",
        "B) Recipients can be modified until dispatch — reasonable middle ground",
        "C) Recipients can be modified at any point before individual delivery — most flexible but operationally complex"
      ],
      "recommendation": "Option B for initial release. Allowing changes up to dispatch avoids mid-route disruption while providing sender flexibility. Can evolve to Option C in a later phase."
    },
    {
      "type": "missing_context",
      "description": "No specification of what 'delivery preferences' encompasses. The spec says 'each Recipient can have different delivery preferences' but does not enumerate what preferences exist. Time windows? Signature requirements? Safe place instructions? Authority to leave? This directly affects the Recipient entity schema.",
      "affected_stakeholders": ["Recipients", "Couriers/Drivers", "Product Team"],
      "options": [
        "A) Define a minimal set now (time window, signature required, safe place instructions) and extend later",
        "B) Make preferences a flexible key-value structure to avoid future schema changes",
        "C) Wait for full product specification of preferences before implementing"
      ],
      "recommendation": "Option A — define a concrete minimal set aligned with industry-standard delivery preferences. A fully generic key-value bag sacrifices domain expressiveness and validation capability."
    }
  ],

  "rejection_reasons": []
}

